private entityToCSVRow(entity: Entity): string {
  const escape = (s: string) => `"${s.replace(/"/g, '""')}"`;
  return [
    escape(entity.name),
    escape(entity.entityType),
    escape(entity.observations.join('; ')),
    escape((entity.tags ?? []).join('; ')),
    entity.importance?.toString() ?? '',
    entity.createdAt ?? '',
    entity.lastModified ?? '',
  ].join(',');
}

